var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"로터스 지사 연구소도 공격 받았답니다!","JPN":"ロータス支社の研究所も攻撃されたそうです！","ENG":"Even the Lotus branch came under attack!","TWN":"洛德斯分公司研究所也遭受攻擊！"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"건설 중에 무너진 연구시설을 수습하는 비용에, 구조된 직원들의 입원비며…….","JPN":"建設中に倒壊した研究施設用の費用に、救助された社員の治療費や……","ENG":"I hear it cost a fortune cleaning up after all the destruction, as well as paying for the rescued employees' hospital bills…","TWN":"建設中倒塌的研究設施整理費，再加上受傷員工的醫療費……"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"현지 태스크포스들까지 고용했는데 당했다던데?","JPN":"現地のタスクフォースカンパニーまで雇ったのにやられたんだってよ？","ENG":"I heard they hired local TASKFORCEs but that didn't do any good!","TWN":"我們還雇傭當地的特遣勢力，也都全軍覆沒嗎？"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"주가가 오늘만 30%가 넘게 빠졌대. 입사할 때 스톡 옵션 받았는데, 젠장…….","JPN":"株価が今日だけで30％以上下がったらしい。入社する時ストックオプションをもらったんだが、ちぇっ……","ENG":"Shares dropped over 30% in a single day. So much for the stock options I got when I joined this company…","TWN":"股價光是今天就已經掉30%，我進公司時還有拿到認股權，該死……"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"범인이 관리국에서 수배 중인 S급 카운터라며? 어쩌다가 그런 인간이랑 척을 진 거래?","JPN":"犯人は管理局が指名手配中のS級カウンターだって？　なぜそんなやつに恨まれてるんだ？","ENG":"I hear the culprit's an S-Grade Counter wanted by the Administration. How does anyone manage to make an enemy out of someone like that?","TWN":"犯人是管理局通緝中的S級制裁者？怎麼會招惹到那種人物？"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"빌어먹을! 수색대는 대체 뭘 한 거야!","JPN":"くそ！　捜索隊はいったい何をしてるんだ！","ENG":"Those bastards! What is the search team even doing?!","TWN":"該死！搜查隊都是幹什麼吃的！"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"수색대 탓 하기 전에 재정 상태부터 신경 쓰지 그래? 10년을 공들인 회사가 며칠만에 먼지만 남게 생겼는데?","JPN":"捜索隊のせいにする前に財政状況を気にしたらどう？\\n10年もかけて育てた会社が、たったの数日で倒産寸前なんだけど。","ENG":"You'd better look after your financial situation if you've got the time to whine about the search team! 10 years of hard work is about to go kaput in a few days.","TWN":"有力氣罵搜查隊，要不要先關心下公司的財務？花10年的時間好不容易建立起來的公司，才幾天內就變成廢墟咧？"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"네가 그 때 끝장을 냈으면 이런 일도 안 생겼어!","JPN":"お前があの時ちゃんと始末しておけばこんなことにはならなかったんだよ！","ENG":"It wouldn't have come to this if you had finished her off right then and there!","TWN":"要是你當時有處理掉她的話，事情會變成這樣嗎！"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_HATE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"상부에 막대한 손해를 봤다는 사실이 알려지기라도 하면…….","JPN":"上層部に莫大な損害が発生した事実を知られたら……","ENG":"If leadership finds out how many losses I suffered…","TWN":"萬一上面發現受到這麼嚴重的損失……"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"그야 버려지겠지.","JPN":"それは捨てられるでしょうね。","ENG":"They'll throw you out to rot on the street, of course.","TWN":"你會完蛋吧～"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"주둥이 닥쳐!!","JPN":"黙れ！！","ENG":"Hold your tongue!!","TWN":"給我閉嘴！！"},"stage":{"bg":"OFFICE","slots":{"L":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_HATE"},"C":null,"R":{"char_id":"WILBURLOVER_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"WILBURLOVER_NPC_NULL_NULL","text":{"KOREA":"자, 자기야. 너무 화내지 마. 무서워.","JPN":"ダ、ダーリン。そんなに怒らないで、怖いよ。","ENG":"B-babe… Please don't get so angry. You're frightening me.","TWN":"親…親愛的，你不要這麼生氣，人家會害怕。"},"stage":{"bg":"OFFICE","slots":{"L":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_HATE"},"C":null,"R":{"char_id":"WILBURLOVER_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"……후우. 아니, 미안해. 조금 놀랐지.","JPN":"……ふぅ。驚かせてごめんね。","ENG":"…Oh. I'm sorry. I must have startled you.","TWN":"……呼，沒事，對不起，你嚇到了吧。"},"stage":{"bg":"OFFICE","slots":{"L":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"WILBURLOVER_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"진정하자. 윌버. 진정하는 거야. 저런 머저리들한테 일을 맡겼으니 당연한 결과야.","JPN":"落ち着け、ウィルバー。落ち着くんだ。あんな間抜けどもに仕事を任せたんだから当然の結果だ。","ENG":"Easy now, Wilbur. Easy. This is what I get for relying on those fools to get the job done.","TWN":"冷靜點，韋爾伯，冷靜。把事情交待給那些蠢蛋，這種結果也是可預期的。"},"stage":{"bg":"OFFICE","slots":{"L":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WILBURLOVER_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"상황이 이렇게 된 이상 이제 유일한 해결책은 그 사채꾼을 잡아다 바치는 수밖에 없어.","JPN":"状況がこうなった以上、唯一の解決策はあの闇金野郎を捕まえて生贄にするしかない。","ENG":"Now that it's come to this, the only solution is to capture that loan shark and offer her as a tribute.","TWN":"事已至此，現在唯一的辦法，就是活捉那個放高利貸的進貢給上面的。"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"그래. 학회의 지원만 있다면 이번에 입은 타격 정도는 얼마든지 복구할 수 있지.","JPN":"そうだ。学会の支援さえあれば、今回の損失なんていくらでも埋め合わせできる。","ENG":"Right. I'm sure with support from the Society, we can more than make up for our losses today.","TWN":"沒錯，只要有學會的資源，這次受到的損失，一定都可以救回來。"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_PRIDE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"중요한 건 내가 그분들이 만족하실 만한 결과를 내놓는지야.","JPN":"大事なのは、あの方たちが満足いくような結果を出せるかどうかだ。","ENG":"The only important thing is to give them something that would please them.","TWN":"重點是我要拿出可以讓他們滿意的結果。"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};